function showNotification(t,e,n){new PNotify({title:t,text:e,type:n,styling:"brighttheme"})}function startScanner(){(new bootstrap.Modal(document.getElementById("qrScannerModal"))).show();let t=new Html5Qrcode("reader");t.start({facingMode:"environment"},{fps:10,qrbox:{width:250,height:250}},((e,n)=>{e.startsWith("http")?(stopScanner(),$("#scanner-status").text("Berhasil! Mengalihkan..."),window.location.href=e):$("#scanner-status").text("QR Code tidak valid!")})).then((()=>{$("#scanner-status").text("Pemindai aktif. Silakan scan QR Code.")})).catch((t=>{$("#scanner-status").text("Gagal mengakses kamera: "+t)}))}function stopScanner(){let t=new Html5Qrcode("reader");t.isScanning&&t.stop().then((t=>{})).catch((t=>{}))}
